import{_ as e,o as i,c as n,ae as l}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Recent Activity (New)","description":"","frontmatter":{"title":"Recent Activity (New)","slug":"recent-activity-new"},"headers":[],"relativePath":"account-hub/recent-activity-new.md","filePath":"account-hub/recent-activity-new.md"}'),r={name:"account-hub/recent-activity-new.md"};function o(a,t,s,c,g,u){return i(),n("div",null,[...t[0]||(t[0]=[l('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <strong>Recent Activity</strong> tab allows you to view changes made in your Branch account within the last 90 days and provides the following benefits:</p><ul><li><strong>Accountability</strong> - View logs of users&#39; actions.</li><li><strong>History</strong> - See edit history for all products, configuration, and more, based on your account timezone.</li><li><strong>Accessibility</strong> - Available to users with <strong>Read</strong> access to <strong>Sensitive Data</strong> and also <strong>Admins</strong>.</li></ul><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Testing &amp; Monitoring page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h2 id="get-started" tabindex="-1">Get started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get started&quot;">​</a></h2><p>To access the Recent Activity page, navigate to <strong>Configuration &gt; Testing &amp; Monitoring</strong> and select the <strong>Recent Activity</strong> tab.</p><p>You can filter the activity log by using the search bar or by selecting a specific feature from the <strong>All features</strong> dropdown.</p><h2 id="supported-features" tabindex="-1">Supported features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported features&quot;">​</a></h2><ul><li><p><strong>Quick Links (Short Links)</strong></p><ul><li>New Short Link created.</li><li>Existing Link edited.</li><li>Existing Link deleted.</li><li>Existing Link archived.</li></ul></li><li><p><strong>Ads</strong></p><ul><li><p><strong>Partner Management</strong></p><ul><li>Partner Enabled/Disabled.</li><li>Partner Settings.</li><li>Postbacks - Edit, enable/disable, delete.</li><li>Attribution Windows.</li></ul></li><li><p><strong>Ad Links.</strong></p></li></ul></li><li><p><strong>Account Settings.</strong></p></li><li><p><strong>Journeys</strong></p><ul><li>Created.</li><li>Edited.</li><li>Changes in Status (Active, Stopped, Archived).</li><li>Changes in Priority.</li><li>Changes in Schedule.</li></ul></li><li><p><strong>Configuration</strong></p><ul><li>General URI Scheme Mode.</li><li>Link Settings.</li></ul></li><li><p><strong>Email</strong></p><ul><li>Partner Enabled/Disabled.</li></ul></li><li><p><strong>Data Feeds</strong></p><ul><li><p><strong>Data Integrations</strong></p><ul><li>Partner Enabled/Disabled.</li></ul></li><li><p><strong>Webhooks</strong></p><ul><li>webhook Enabled/Deleted/Archived.</li></ul></li><li><p><strong>Settings.</strong></p></li></ul></li><li><p><strong>SKAdNetwork</strong></p><ul><li>Created/Updated/Deleted Conversion Value.</li></ul></li></ul>',9)])])}const h=e(r,[["render",o]]);export{p as __pageData,h as default};
